import bisect

class Inventory:
    def __init__(self):
        self._skus = []
        self._products = []

    def _validate_sku(self, sku):
        if not isinstance(sku, str) or not sku.isalnum() or len(sku) < 6 or len(sku) > 12:
            raise ValueError("Invalid SKU format")

    def add_product(self, sku, product_data):
        self._validate_sku(sku)
        index = bisect.bisect_left(self._skus, sku)
        if index < len(self._skus) and self._skus[index] == sku:
            raise ValueError("Duplicate SKU")
        bisect.insort(self._skus, sku)
        self._products.insert(index, product_data)

    def search_by_sku(self, sku):
        self._validate_sku(sku)
        index = bisect.bisect_left(self._skus, sku)
        if index < len(self._skus) and self._skus[index] == sku:
            return self._products[index]
        raise KeyError("SKU not found")

    def delete_product(self, sku):
        self._validate_sku(sku)
        index = bisect.bisect_left(self._skus, sku)
        if index < len(self._skus) and self._skus[index] == sku:
            del self._skus[index]
            del self._products[index]
        else:
            raise KeyError("SKU not found")

    def update_product(self, sku, new_data):
        index = bisect.bisect_left(self._skus, sku)
        if index < len(self._skus) and self._skus[index] == sku:
            self._products[index] = new_data
        else:
            raise KeyError("SKU not found")
