#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_SEATS 100

typedef struct Node {
    int seatNumber;
    struct Node* next;
} Node;

typedef struct {
    Node* front;
    Node* rear;
} Queue;

Queue* createQueue() {
    Queue* q = (Queue*)malloc(sizeof(Queue));
    q->front = q->rear = NULL;
    return q;
}

bool isEmpty(Queue* q) {
    return q->front == NULL;
}

void enqueue(Queue* q, int seat) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->seatNumber = seat;
    newNode->next = NULL;
    if (q->rear == NULL) {
        q->front = q->rear = newNode;
    } else {
        q->rear->next = newNode;
        q->rear = newNode;
    }
}

int dequeue(Queue* q) {
    if (isEmpty(q)) return -1;
    Node* temp = q->front;
    int seat = temp->seatNumber;
    q->front = q->front->next;
    if (q->front == NULL) q->rear = NULL;
    free(temp);
    return seat;
}

void initializeSeats(Queue* q) {
    for (int i = 1; i <= MAX_SEATS; i++) enqueue(q, i);
}

bool bookedSeats[MAX_SEATS + 1] = {false};

int main() {
    Queue* seatQueue = createQueue();
    initializeSeats(seatQueue);
    int choice;
    while (1) {
        printf("\n1. Book Ticket\n2. Cancel Ticket\n3. Display Available Seats\n4. Exit\nEnter choice: ");
        scanf("%d", &choice);
        switch (choice) {
            case 1: {
                int seat = dequeue(seatQueue);
                if (seat == -1) printf("Overbooking: No seats available.\n");
                else {
                    bookedSeats[seat] = true;
                    printf("Seat %d booked.\n", seat);
                }
                break;
            }
            case 2: {
                int seat;
                printf("Enter seat: ");
                scanf("%d", &seat);
                if (seat < 1 || seat > MAX_SEATS) printf("Invalid seat.\n");
                else if (!bookedSeats[seat]) printf("Seat %d not booked.\n", seat);
                else {
                    enqueue(seatQueue, seat);
                    bookedSeats[seat] = false;
                    printf("Seat %d cancelled.\n", seat);
                }
                break;
            }
            case 3: {
                Node* current = seatQueue->front;
                printf("Available: ");
                while (current) {
                    printf("%d ", current->seatNumber);
                    current = current->next;
                }
                printf("\n");
                break;
            }
            case 4:
                exit(0);
            default:
                printf("Invalid choice.\n");
        }
    }
    return 0;
}
