use rand::Rng;
use std::error::Error;

pub fn shuffle<T>(arr: &mut [T]) -> Result<(), Box<dyn Error>> {
    if arr.is_empty() {
        return Err("Array must not be empty".into());
    }
    let mut rng = rand::thread_rng();
    for i in (1..arr.len()).rev() {
        let j = rng.gen_range(0..=i);
        arr.swap(i, j);
    }
    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
    let mut nums = [1, 2, 3, 4, 5];
    shuffle(&mut nums)?;
    println!("Shuffled: {:?}", nums);

    let mut words = ["apple", "banana", "cherry"];
    shuffle(&mut words)?;
    println!("Shuffled: {:?}", words);

    let mut empty: [i32; 0] = [];
    if let Err(e) = shuffle(&mut empty) {
        println!("Error: {}", e);
    }

    Ok(())
}
