using namespace std;

struct LogEntry {
    long timestamp;
    string event;
    LogEntry(long t, const string& e) : timestamp(t), event(e) {}
};

bool operator<(const LogEntry& a, const LogEntry& b) {
    return a.timestamp < b.timestamp;
}

class LogManager {
private:
    multiset<LogEntry> logs;

public:
    void addLog(long timestamp, const string& event) {
        logs.emplace(timestamp, event);
    }

    vector<LogEntry> queryRange(long start, long end) {
        vector<LogEntry> result;
        auto it_low = logs.lower_bound(LogEntry(start, ""));
        auto it_high = logs.upper_bound(LogEntry(end, ""));
        for (auto it = it_low; it != it_high; ++it)
            result.push_back(*it);
        return result;
    }
};

int main() {
    LogManager manager;
    manager.addLog(1617900000, "User login");
    manager.addLog(1617900005, "File upload");
    manager.addLog(1617900010, "Error occurred");
    manager.addLog(1617900010, "System update");
    auto logs = manager.queryRange(1617900005, 1617900010);
    for (const auto& log : logs)
        cout << "Timestamp: " << log.timestamp << ", Event: " << log.event << endl;
    return 0;
}
