import java.util.HashMap;
import java.util.Map;

class DynamicLCA {
    private static final int MAX_LOG = 20;
    private final Map<Integer, int[]> up = new HashMap<>();
    private final Map<Integer, Integer> depth = new HashMap<>();
    private final Map<Integer, Integer> parent = new HashMap<>();

    public DynamicLCA(int root) {
        parent.put(root, -1);
        depth.put(root, 0);
        int[] jumps = new int[MAX_LOG];
        java.util.Arrays.fill(jumps, -1);
        up.put(root, jumps);
    }

    public void addNode(int node, int parentNode) {
        parent.put(node, parentNode);
        depth.put(node, depth.get(parentNode) + 1);
        int[] jumps = new int[MAX_LOG];
        jumps[0] = parentNode;
        for (int i = 1; i < MAX_LOG; i++) {
            int prev = jumps[i - 1];
            jumps[i] = prev != -1 ? up.get(prev)[i - 1] : -1;
        }
        up.put(node, jumps);
    }

    public void updateParent(int node, int newParent) {
        parent.put(node, newParent);
        depth.put(node, depth.get(newParent) + 1);
        int[] jumps = up.get(node);
        jumps[0] = newParent;
        for (int i = 1; i < MAX_LOG; i++) {
            int prev = jumps[i - 1];
            jumps[i] = prev != -1 ? up.get(prev)[i - 1] : -1;
        }
    }

    public int findLCA(int u, int v) {
        if (depth.get(u) < depth.get(v)) {
            int temp = u;
            u = v;
            v = temp;
        }

        for (int i = MAX_LOG - 1; i >= 0; i--) {
            if (depth.get(u) - (1 << i) >= depth.get(v)) {
                u = up.get(u)[i];
            }
        }

        if (u == v) return u;

        for (int i = MAX_LOG - 1; i >= 0; i--) {
            int pu = up.get(u)[i];
            int pv = up.get(v)[i];
            if (pu != pv) {
                u = pu;
                v = pv;
            }
        }

        return up.get(u)[0];
    }
}
