#include <cctype>
#include <memory>
#include <stdexcept>

using namespace std;
namespace fs = filesystem;

class Document {
public:
    int id;
    string content;
    Document(int id, const string& content) : id(id), content(content) {}
};

class DocumentParser {
public:
    virtual ~DocumentParser() = default;
    virtual string parse(const string& path) const = 0;
};

class TxtParser : public DocumentParser {
public:
    string parse(const string& path) const override {
        ifstream file(path);
        if (!file) throw runtime_error("Failed to open: " + path);
        stringstream buffer;
        buffer << file.rdbuf();
        return buffer.str();
    }
};

class InvertedIndex {
private:
    unordered_map<string, set<int>> index;
    vector<string> tokenize(const string& text) {
        unordered_set<string> tokens;
        string token;
        for (char c : text) {
            if (isalnum(c)) token += tolower(c);
            else if (!token.empty()) { tokens.insert(token); token.clear(); }
        }
        if (!token.empty()) tokens.insert(token);
        return vector<string>(tokens.begin(), tokens.end());
    }

public:
    void addDocument(const Document& doc) {
        for (const auto& token : tokenize(doc.content)) {
            index[token].insert(doc.id);
        }
    }

    set<int> search(const string& term) const {
        auto it = index.find(term);
        return it != index.end() ? it->second : set<int>();
    }
};

class DocumentLoader {
private:
    InvertedIndex& index;
    int docCounter = 1;
    unique_ptr<DocumentParser> getParser(const string& path) {
        string ext = fs::path(path).extension().string();
        if (ext == ".txt") return make_unique<TxtParser>();
        throw runtime_error("Unsupported format: " + ext);
    }

public:
    DocumentLoader(InvertedIndex& idx) : index(idx) {}
    void load(const string& path) {
        try {
            auto parser = getParser(path);
            Document doc(docCounter++, parser->parse(path));
            index.addDocument(doc);
        } catch (const exception& e) {
            cerr << "Skipped " << path << " - Error: " << e.what() << endl;
        }
    }
};

int main() {
    InvertedIndex idx;
    DocumentLoader loader(idx);
    for (const auto& entry : fs::directory_iterator("docs/")) {
        loader.load(entry.path().string());
    }
    return 0;
}
