use num_bigint::BigUint;
use num_traits::{Zero, One, FromPrimitive};
use std::fs::File;
use std::io::{BufRead, BufReader};
use std::env;

fn is_prime(n: &BigUint) -> bool {
    if n <= &BigUint::one() {
        return false;
    }
    if n == &BigUint::from(2u8) || n == &BigUint::from(3u8) {
        return true;
    }
    if n % 2u8 == BigUint::zero() {
        return false;
    }

    let mut d = n - BigUint::one();
    let mut s = 0;
    while &d % 2u8 == BigUint::zero() {
        d /= 2u8;
        s += 1;
    }

    let bases = [2u8, 3u8, 5u8, 7u8, 11u8, 13u8, 17u8, 19u8, 23u8, 29u8, 31u8, 37u8];
    for a in bases.iter() {
        let a_big = BigUint::from(*a);
        if a_big >= *n {
            continue;
        }
        let mut x = a_big.modpow(&d, n);
        if x == BigUint::one() || x == n - BigUint::one() {
            continue;
        }
        let mut found = false;
        for _ in 0..s - 1 {
            x = x.modpow(&BigUint::from(2u8), n);
            if x == n - BigUint::one() {
                found = true;
                break;
            }
        }
        if !found {
            return false;
        }
    }
    true
}

fn main() {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        eprintln!("Usage: {} <input_file>", args[0]);
        std::process::exit(1);
    }

    let file = File::open(&args[1]).unwrap_or_else(|_| {
        eprintln!("Cannot open file: {}", args[1]);
        std::process::exit(1);
    });

    let reader = BufReader::new(file);

    for line in reader.lines() {
        let line = line.unwrap_or_else(|_| {
            eprintln!("Error reading line");
            std::process::exit(1);
        });

        let num = line.trim().parse::<BigUint>().unwrap_or_else(|_| {
            eprintln!("Invalid input: {}", line.trim());
            std::process::exit(1);
        });

        println!("{} {}", num, if is_prime(&num) { "prime" } else { "not prime" });
    }
}
