import java.io.*;
import java.util.HashMap;
import java.util.Scanner;

class Item implements Serializable {
    private String id;
    private String name;
    private int quantity;

    public Item(String id, String name, int quantity) {
        this.id = id;
        this.name = name;
        this.quantity = quantity;
    }

    public String getId() { return id; }
    public String getName() { return name; }
    public int getQuantity() { return quantity; }
    public void setQuantity(int quantity) { this.quantity = quantity; }

    @Override
    public String toString() {
        return "Item{id='" + id + "', name='" + name + "', quantity=" + quantity + "}";
    }
}

public class InventoryManager implements Serializable {
    private HashMap<String, Item> inventory = new HashMap<>();

    public void addItem(String id, String name, int quantity) {
        inventory.put(id, new Item(id, name, quantity));
    }

    public Item removeItem(String id) {
        return inventory.remove(id);
    }

    public Item findItem(String id) {
        return inventory.get(id);
    }

    public void saveToFile(String filename) {
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(filename))) {
            oos.writeObject(this);
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    public static InventoryManager loadFromFile(String filename) {
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(filename))) {
            return (InventoryManager) ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
            return new InventoryManager();
        }
    }

    public static void main(String[] args) {
        InventoryManager manager = new InventoryManager();
        Scanner scanner = new Scanner(System.in);

        while (true) {
            System.out.println("Enter command (add, remove, find, save, load, exit):");
            String command = scanner.nextLine();

            if (command.equalsIgnoreCase("exit")) break;

            switch (command.toLowerCase()) {
                case "add":
                    System.out.println("Enter ID:");
                    String id = scanner.nextLine();
                    System.out.println("Enter name:");
                    String name = scanner.nextLine();
                    System.out.println("Enter quantity:");
                    int quantity = Integer.parseInt(scanner.nextLine());
                    manager.addItem(id, name, quantity);
                    break;
                case "remove":
                    System.out.println("Enter ID to remove:");
                    Item removed = manager.removeItem(scanner.nextLine());
                    System.out.println(removed != null ? "Removed: " + removed : "Item not found");
                    break;
                case "find":
                    System.out.println("Enter ID to find:");
                    Item found = manager.findItem(scanner.nextLine());
                    System.out.println(found != null ? "Found: " + found : "Item not found");
                    break;
                case "save":
                    System.out.println("Enter filename to save:");
                    manager.saveToFile(scanner.nextLine());
                    break;
                case "load":
                    System.out.println("Enter filename to load:");
                    manager = InventoryManager.loadFromFile(scanner.nextLine());
                    break;
                default:
                    System.out.println("Unknown command");
            }
        }
        scanner.close();
    }
}
