#include <iostream>
#include <fstream>
#include <map>
#include <vector>
#include <string>
#include <algorithm>

using namespace std;

struct Node {
    int start;
    int* end;
    Node* suffix_link;
    map<char, Node*> children;
    int index;

    Node(int start, int* end) : start(start), end(end), suffix_link(nullptr), index(-1) {}
    int edge_length() { return *end - start + 1; }
};

class SuffixTree {
public:
    Node* root;
    Node* active_node;
    char active_edge;
    int active_length;
    int remaining;
    int global_end;
    string text;

    SuffixTree(string txt) : text(txt), global_end(-1), remaining(0), active_edge('\0'), active_length(0) {
        root = new Node(-1, new int(-1));
        active_node = root;
        build();
    }

    void build() {
        for (int i = 0; i < text.size(); i++) {
            extend_suffix_tree(i);
        }
        set_index(root, 0);
    }

    void extend_suffix_tree(int pos) {
        global_end = pos;
        remaining++;
        Node* last_new_node = nullptr;

        while (remaining > 0) {
            if (active_length == 0) active_edge = text[pos];

            if (active_node->children.find(active_edge) == active_node->children.end()) {
                active_node->children[active_edge] = new Node(pos, &global_end);
                if (last_new_node != nullptr) {
                    last_new_node->suffix_link = active_node;
                    last_new_node = nullptr;
                }
            } else {
                Node* next = active_node->children[active_edge];
                if (walk_down(next)) continue;

                if (text[next->start + active_length] == text[pos]) {
                    active_length++;
                    if (last_new_node != nullptr && active_node != root) {
                        last_new_node->suffix_link = active_node;
                        last_new_node = nullptr;
                    }
                    break;
                }

                Node* split = new Node(next->start, new int(next->start + active_length - 1));
                active_node->children[active_edge] = split;
                split->children[text[pos]] = new Node(pos, &global_end);
                next->start += active_length;
                split->children[text[next->start]] = next;
                if (last_new_node != nullptr) last_new_node->suffix_link = split;
                last_new_node = split;
            }

            remaining--;
            if (active_node == root && active_length > 0) {
                active_length--;
                active_edge = text[pos - remaining + 1];
            } else if (active_node != root) {
                active_node = active_node->suffix_link ? active_node->suffix_link : root;
            }
        }
    }

    bool walk_down(Node* node) {
        int edge_len = node->edge_length();
        if (active_length >= edge_len) {
            active_edge += edge_len;
            active_length -= edge_len;
            active_node = node;
            return true;
        }
        return false;
    }

    void set_index(Node* node, int label_height) {
        if (node == nullptr) return;

        bool leaf = true;
        for (auto& child : node->children) {
            leaf = false;
            set_index(child.second, label_height + child.second->edge_length());
        }

        if (leaf) {
            node->index = text.size() - label_height;
        }
    }

    vector<int> search(const string& pattern) {
        vector<int> positions;
        Node* current = root;
        int pattern_ptr = 0;

        while (pattern_ptr < pattern.size()) {
            char c = pattern[pattern_ptr];
            if (current->children.find(c) == current->children.end()) return positions;

            current = current->children[c];
            int edge_len = current->edge_length();
            for (int i = 0; i < edge_len && pattern_ptr < pattern.size(); i++, pattern_ptr++) {
                if (text[current->start + i] != pattern[pattern_ptr]) return positions;
            }
        }

        collect_leaf_indices(current, positions);
        sort(positions.begin(), positions.end());
        return positions;
    }

    void collect_leaf_indices(Node* node, vector<int>& indices) {
        if (node == nullptr) return;
        if (node->index != -1) {
            indices.push_back(node->index);
            return;
        }
        for (auto& child : node->children) {
            collect_leaf_indices(child.second, indices);
        }
    }
};

int main(int argc, char* argv[]) {
    if (argc != 3) {
        cerr << "Usage: " << argv[0] << " <text_file> <query>" << endl;
        return 1;
    }

    string query = argv[2];
    if (query.empty()) {
        cerr << "Error: Query cannot be empty." << endl;
        return 1;
    }

    ifstream file(argv[1]);
    if (!file.is_open()) {
        cerr << "Error: Unable to open file." << endl;
        return 1;
    }

    string text((istreambuf_iterator<char>(file)), istreambuf_iterator<char>());
    file.close();

    if (text.empty()) {
        cerr << "Error: Input text is empty." << endl;
        return 1;
    }

    text += '$';
    SuffixTree st(text);

    vector<int> occurrences = st.search(query);
    if (occurrences.empty()) {
        cout << "Substring not found." << endl;
    } else {
        cout << "Occurrences found at positions:";
        for (int pos : occurrences) {
            cout << " " << pos;
        }
        cout << endl;
    }

    return 0;
}
