#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <string.h>
#include <time.h>

typedef struct {
    double* data;
    int size;
    int capacity;
    int is_max_heap;
} Heap;

Heap* max_heap;
Heap* min_heap;
pthread_mutex_t heaps_mutex = PTHREAD_MUTEX_INITIALIZER;
pthread_mutex_t log_mutex = PTHREAD_MUTEX_INITIALIZER;

Heap* create_heap(int capacity, int is_max_heap) {
    Heap* heap = malloc(sizeof(Heap));
    heap->data = malloc(sizeof(double) * capacity);
    heap->size = 0;
    heap->capacity = capacity;
    heap->is_max_heap = is_max_heap;
    return heap;
}

void swap(double* a, double* b) { double t = *a; *a = *b; *b = t; }

void heapify_up(Heap* h, int i) {
    while (i > 0) {
        int p = (i - 1) / 2;
        if ((h->is_max_heap && h->data[i] > h->data[p]) || (!h->is_max_heap && h->data[i] < h->data[p])) {
            swap(&h->data[i], &h->data[p]);
            i = p;
        } else break;
    }
}

void heapify_down(Heap* h, int i) {
    while (1) {
        int l = 2 * i + 1, r = 2 * i + 2, e = i;
        if (l < h->size && ((h->is_max_heap && h->data[l] > h->data[e]) || (!h->is_max_heap && h->data[l] < h->data[e]))) e = l;
        if (r < h->size && ((h->is_max_heap && h->data[r] > h->data[e]) || (!h->is_max_heap && h->data[r] < h->data[e]))) e = r;
        if (e == i) break;
        swap(&h->data[i], &h->data[e]);
        i = e;
    }
}

void heap_insert(Heap* h, double v) {
    if (h->size == h->capacity) return;
    h->data[h->size++] = v;
    heapify_up(h, h->size - 1);
}

double heap_extract(Heap* h) {
    double v = h->data[0];
    h->data[0] = h->data[--h->size];
    heapify_down(h, 0);
    return v;
}

double heap_peek(Heap* h) { return h->size > 0 ? h->data[0] : 0; }

void log_error(const char* id, const char* msg) {
    pthread_mutex_lock(&log_mutex);
    time_t t = time(NULL);
    printf("[%.19s] Sensor %s: %s\n", ctime(&t), id, msg);
    pthread_mutex_unlock(&log_mutex);
}

void* sensor_thread(void* arg) {
    char* id = ((char**)arg)[0];
    char* file = ((char**)arg)[1];
    free(arg);

    FILE* fp = fopen(file, "r");
    if (!fp) { log_error(id, "Connection failed"); free(id); free(file); return NULL; }

    char line[256];
    while (fgets(line, sizeof(line), fp)) {
        double temp;
        if (sscanf(line, "%lf", &temp) != 1) { log_error(id, "Invalid data"); continue; }

        pthread_mutex_lock(&heaps_mutex);
        if (max_heap->size == 0 || temp <= heap_peek(max_heap)) heap_insert(max_heap, temp);
        else heap_insert(min_heap, temp);

        if (max_heap->size > min_heap->size + 1) heap_insert(min_heap, heap_extract(max_heap));
        else if (min_heap->size > max_heap->size) heap_insert(max_heap, heap_extract(min_heap));

        double median = (max_heap->size == min_heap->size) ? (heap_peek(max_heap) + heap_peek(min_heap)) / 2 : heap_peek(max_heap);
        pthread_mutex_unlock(&heaps_mutex);

        printf("Median: %.2f\n", median);
    }

    if (ferror(fp)) log_error(id, "Read error");
    fclose(fp);
    free(id); free(file);
    return NULL;
}

int main() {
    max_heap = create_heap(1000, 1);
    min_heap = create_heap(1000, 0);

    char cmd[256];
    while (printf("> "), fgets(cmd, sizeof(cmd), stdin)) {
        if (strncmp(cmd, "ADD", 3) == 0) {
            char id[64], file[256];
            if (sscanf(cmd + 4, "%63s %255s", id, file) != 2) { fprintf(stderr, "Invalid command\n"); continue; }

            char** arg = malloc(2 * sizeof(char*));
            arg[0] = strdup(id);
            arg[1] = strdup(file);

            pthread_t t;
            if (pthread_create(&t, NULL, sensor_thread, arg) != 0) { free(arg[0]); free(arg[1]); free(arg); }
            else pthread_detach(t);
        } else fprintf(stderr, "Unknown command\n");
    }
    return 0;
}
