function findLongestCommonSubsequence(word1, word2) {
    if (typeof word1 !== 'string' || typeof word2 !== 'string') throw new Error('Invalid input: both words must be strings');
    if (word1.length === 0 || word2.length === 0) return '';

    const indexMap = new Map();
    for (let i = word2.length - 1; i >= 0; i--) {
        const char = word2[i];
        if (!indexMap.has(char)) indexMap.set(char, []);
        indexMap.get(char).push(i);
    }

    const sequence = [];
    for (const char of word1) {
        const indices = indexMap.get(char);
        if (indices) sequence.push(...indices);
    }

    if (sequence.length === 0) return '';

    const lisIndices = longestIncreasingSubsequence(sequence);
    return lisIndices.map(i => word2[i]).join('');
}

function longestIncreasingSubsequence(arr) {
    const tails = [];
    const prev = new Array(arr.length).fill(-1);

    for (let i = 0; i < arr.length; i++) {
        let left = 0, right = tails.length;
        while (left < right) {
            const mid = (left + right) >> 1;
            if (arr[tails[mid]] < arr[i]) left = mid + 1;
            else right = mid;
        }
        if (left > 0) prev[i] = tails[left - 1];
        if (left === tails.length) tails.push(i);
        else tails[left] = i;
    }

    const result = [];
    let curr = tails[tails.length - 1];
    while (curr !== undefined && curr !== -1) {
        result.push(arr[curr]);
        curr = prev[curr];
    }
    return result.reverse();
}
