#include <iostream>
#include <vector>
#include <algorithm>
#include <string>

using namespace std;

struct Book {
    string title;
    int edition;
};

bool compareBooks(const Book &a, const Book &b) {
    return (a.title == b.title) ? (a.edition < b.edition) : (a.title < b.title);
}

class Library {
private:
    vector<Book> books;

public:
    bool addBook(const string &title, int edition) {
        if (title.empty() || edition < 1) return false;
        Book newBook{title, edition};
        auto it = lower_bound(books.begin(), books.end(), newBook, compareBooks);
        if (it != books.end() && it->title == title && it->edition == edition) return false;
        books.insert(it, newBook);
        return true;
    }

    bool removeBook(const string &title, int edition) {
        if (title.empty() || edition < 1) return false;
        Book target{title, edition};
        auto it = lower_bound(books.begin(), books.end(), target, compareBooks);
        if (it != books.end() && it->title == title && it->edition == edition) {
            books.erase(it);
            return true;
        }
        return false;
    }

    vector<Book> searchByTitle(const string &title) {
        vector<Book> result;
        if (title.empty()) return result;
        Book dummy{title, 0};
        auto it = lower_bound(books.begin(), books.end(), dummy, compareBooks);
        while (it != books.end() && it->title == title) {
            result.push_back(*it);
            ++it;
        }
        return result;
    }

    void listAllBooks() {
        for (const auto &book : books) {
            cout << "Title: " << book.title << ", Edition: " << book.edition << endl;
        }
    }
};

int main() {
    Library lib;
    int choice;
    string title;
    int edition;

    do {
        cout << "\nLibrary Catalog Management\n1. Add Book\n2. Remove Book\n3. Search by Title\n4. List All Books\n5. Exit\nEnter choice: ";
        cin >> choice;
        cin.ignore();

        switch (choice) {
            case 1:
                cout << "Enter title: ";
                getline(cin, title);
                cout << "Enter edition: ";
                cin >> edition;
                cout << (lib.addBook(title, edition) ? "Book added successfully.\n" : "Invalid input or book already exists.\n");
                cin.ignore();
                break;
            case 2:
                cout << "Enter title: ";
                getline(cin, title);
                cout << "Enter edition: ";
                cin >> edition;
                cout << (lib.removeBook(title, edition) ? "Book removed successfully.\n" : "Book not found or invalid input.\n");
                cin.ignore();
                break;
            case 3:
                cout << "Enter title to search: ";
                getline(cin, title);
                {
                    vector<Book> results = lib.searchByTitle(title);
                    if (results.empty()) cout << "No books found with that title.\n";
                    else for (const auto &book : results) cout << "Title: " << book.title << ", Edition: " << book.edition << endl;
                }
                break;
            case 4:
                lib.listAllBooks();
                break;
            case 5:
                cout << "Exiting...\n";
                break;
            default:
                cout << "Invalid choice. Try again.\n";
        }
    } while (choice != 5);

    return 0;
}
