#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <math.h>

#define WINDOW 600
#define TEMP_MIN -50.0
#define TEMP_MAX 150.0
#define GLITCH_THRESHOLD 15.0

typedef struct Node {
    time_t timestamp;
    double temp;
    struct Node* next;
} Node;

typedef struct Sensor {
    char id[64];
    Node* head;
    Node* tail;
    double sum;
    int count;
    struct Sensor* next;
} Sensor;

Sensor* sensors = NULL;

Sensor* get_sensor(const char* id) {
    Sensor* curr = sensors;
    while (curr) {
        if (strcmp(curr->id, id) == 0) return curr;
        curr = curr->next;
    }
    Sensor* new = malloc(sizeof(Sensor));
    strncpy(new->id, id, sizeof(new->id)-1);
    new->head = new->tail = NULL;
    new->sum = 0;
    new->count = 0;
    new->next = sensors;
    sensors = new;
    return new;
}

void process_data(const char* id, time_t ts, double temp) {
    Sensor* s = get_sensor(id);

    if (temp < TEMP_MIN || temp > TEMP_MAX) {
        if (s->count > 0) temp = s->sum / s->count;
        else return;
    } else if (s->count > 0) {
        double avg = s->sum / s->count;
        if (fabs(temp - avg) > GLITCH_THRESHOLD) temp = avg;
    }

    Node* new = malloc(sizeof(Node));
    new->timestamp = ts;
    new->temp = temp;
    new->next = NULL;

    if (!s->head) s->head = s->tail = new;
    else s->tail->next = new, s->tail = new;

    s->sum += temp;
    s->count++;

    time_t cutoff = ts - WINDOW;
    while (s->head && s->head->timestamp < cutoff) {
        Node* old = s->head;
        s->sum -= old->temp;
        s->count--;
        s->head = old->next;
        free(old);
        if (!s->head) s->tail = NULL;
    }
}

int main() {
    time_t now = time(NULL);
    process_data("s1", now, 25.5);
    process_data("s1", now+1, 26.0);
    process_data("s2", now+2, 200.0);
    process_data("s1", now+3, 50.0);
    process_data("s1", now+WINDOW+1, 27.0);
    return 0;
}
