class BTreeNode {
    constructor(isLeaf = true) {
        this.keys = [];
        this.children = [];
        this.isLeaf = isLeaf;
    }
}

class BTree {
    constructor(order = 3) {
        this.root = new BTreeNode(true);
        this.order = order;
        this.minKeys = order - 1;
    }

    insert(book) {
        const root = this.root;
        if (root.keys.length === 2 * this.order - 1) {
            const newRoot = new BTreeNode(false);
            newRoot.children.push(this.root);
            this.root = newRoot;
            this.splitChild(newRoot, 0);
        }
        this.insertNonFull(this.root, book);
    }

    splitChild(parent, index) {
        const child = parent.children[index];
        const newChild = new BTreeNode(child.isLeaf);
        const t = this.order;

        newChild.keys = child.keys.splice(t, t - 1);
        if (!child.isLeaf) {
            newChild.children = child.children.splice(t, t);
        }
        parent.keys.splice(index, 0, child.keys.splice(t - 1, 1)[0]);
        parent.children.splice(index + 1, 0, newChild);
    }

    insertNonFull(node, book) {
        let i = node.keys.length - 1;
        if (node.isLeaf) {
            while (i >= 0 && book.title.localeCompare(node.keys[i].title) < 0) {
                i--;
            }
            node.keys.splice(i + 1, 0, book);
        } else {
            while (i >= 0 && book.title.localeCompare(node.keys[i].title) < 0) {
                i--;
            }
            i++;
            const child = node.children[i];
            if (child.keys.length === 2 * this.order - 1) {
                this.splitChild(node, i);
                if (book.title.localeCompare(node.keys[i].title) > 0) {
                    i++;
                }
            }
            this.insertNonFull(node.children[i], book);
        }
    }

    search(title) {
        return this.searchNode(this.root, title);
    }

    searchNode(node, title) {
        let i = 0;
        while (i < node.keys.length && title.localeCompare(node.keys[i].title) > 0) {
            i++;
        }
        if (i < node.keys.length && node.keys[i].title === title) {
            return node.keys[i];
        } else if (node.isLeaf) {
            return null;
        } else {
            return this.searchNode(node.children[i], title);
        }
    }

    delete(title) {
        this.deleteKey(this.root, title);
        if (this.root.keys.length === 0 && !this.root.isLeaf) {
            this.root = this.root.children[0];
        }
    }

    deleteKey(node, title) {
        const idx = this.findKeyIndex(node, title);
        if (idx < node.keys.length && node.keys[idx].title === title) {
            if (node.isLeaf) {
                this.removeFromLeaf(node, idx);
            } else {
                this.removeFromInternal(node, idx);
            }
        } else {
            if (node.isLeaf) return;
            const flag = idx === node.keys.length;
            if (node.children[idx].keys.length <= this.minKeys) {
                this.fill(node, idx);
            }
            this.deleteKey(flag ? node.children[idx - 1] : node.children[idx], title);
        }
    }

    removeFromLeaf(node, idx) {
        node.keys.splice(idx, 1);
    }

    removeFromInternal(node, idx) {
        const key = node.keys[idx];
        if (node.children[idx].keys.length > this.minKeys) {
            const predecessor = this.getPredecessor(node, idx);
            node.keys[idx] = predecessor;
            this.deleteKey(node.children[idx], predecessor.title);
        } else if (node.children[idx + 1].keys.length > this.minKeys) {
            const successor = this.getSuccessor(node, idx);
            node.keys[idx] = successor;
            this.deleteKey(node.children[idx + 1], successor.title);
        } else {
            this.merge(node, idx);
            this.deleteKey(node.children[idx], key.title);
        }
    }

    getPredecessor(node, idx) {
        let current = node.children[idx];
        while (!current.isLeaf) current = current.children[current.keys.length];
        return current.keys[current.keys.length - 1];
    }

    getSuccessor(node, idx) {
        let current = node.children[idx + 1];
        while (!current.isLeaf) current = current.children[0];
        return current.keys[0];
    }

    fill(node, idx) {
        if (idx !== 0 && node.children[idx - 1].keys.length > this.minKeys) {
            this.borrowFromPrev(node, idx);
        } else if (idx !== node.keys.length && node.children[idx + 1].keys.length > this.minKeys) {
            this.borrowFromNext(node, idx);
        } else {
            this.merge(node, idx === node.keys.length ? idx - 1 : idx);
        }
    }

    borrowFromPrev(node, idx) {
        const child = node.children[idx];
        const sibling = node.children[idx - 1];
        child.keys.unshift(node.keys[idx - 1]);
        if (!child.isLeaf) child.children.unshift(sibling.children.pop());
        node.keys[idx - 1] = sibling.keys.pop();
    }

    borrowFromNext(node, idx) {
        const child = node.children[idx];
        const sibling = node.children[idx + 1];
        child.keys.push(node.keys[idx]);
        if (!child.isLeaf) child.children.push(sibling.children.shift());
        node.keys[idx] = sibling.keys.shift();
    }

    merge(node, idx) {
        const child = node.children[idx];
        const sibling = node.children[idx + 1];
        child.keys.push(node.keys.splice(idx, 1)[0]);
        child.keys.push(...sibling.keys);
        if (!child.isLeaf) child.children.push(...sibling.children);
        node.children.splice(idx + 1, 1);
    }

    findKeyIndex(node, title) {
        let idx = 0;
        while (idx < node.keys.length && title.localeCompare(node.keys[idx].title) > 0) idx++;
        return idx;
    }
}

const fs = require('fs');

class BookCatalog {
    constructor() {
        this.tree = new BTree(3);
    }

    loadFromJSON(filePath) {
        try {
            const data = JSON.parse(fs.readFileSync(filePath, 'utf8'));
            data.forEach(book => this.insertBook(book));
        } catch (error) {
