        if (this.tree.search(book.title)) {
            console.error('Duplicate title:', book.title);
            return false;
        }
        this.tree.insert(book);
        return true;
    }

    searchBook(title) {
        return this.tree.search(title);
    }

    deleteBook(title) {
        if (!this.tree.search(title)) return false;
        this.tree.delete(title);
        return true;
    }

    validateBook(book) {
        return book && typeof book.title === 'string' && typeof book.author === 'string';
    }
}
