class UserActivityAnalyzer {
private:
    std::unordered_map<std::string, int> userCounts;
    size_t errorCount = 0;

    void processLine(const std::string& line) {
        size_t delim = line.find(',');
        if (delim == std::string::npos || line.empty()) {
            errorCount++;
            return;
        }
        userCounts[line.substr(0, delim)]++;
    }

public:
    void processLogs(const std::string& path) {
        std::ifstream file(path);
        if (!file) throw std::runtime_error("File open failed: " + path);

        std::string line;
        while (std::getline(file, line)) {
            try {
                processLine(line);
            } catch (...) {
                errorCount++;
            }
        }
    }

    void updateUser(const std::string& user) {
        userCounts[user]++;
    }

    std::vector<std::pair<std::string, int>> getTopK(size_t k) {
        std::vector<std::pair<std::string, int>> users(userCounts.begin(), userCounts.end());
        std::sort(users.begin(), users.end(), 
            [](const auto& a, const auto& b) { return a.second > b.second; });

        if (k > users.size()) k = users.size();
        return { users.begin(), users.begin() + k };
    }

    size_t getErrorCount() const { return errorCount; }
};

int main() {
    UserActivityAnalyzer analyzer;
    try {
        analyzer.processLogs("activity.log");
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    auto top = analyzer.getTopK(10);
    for (const auto& user : top) {
        std::cout << user.first << "\t" << user.second << std::endl;
    }
    std::cout << "Errors: " << analyzer.getErrorCount() << std::endl;
    return 0;
}
