use std::io;

fn main() {
    let n = loop {
        println!("Enter the board dimension (n):");
        let mut input = String::new();
        io::stdin().read_line(&mut input).expect("Failed to read line");
        match input.trim().parse::<usize>() {
            Ok(num) if num > 0 => break num,
            Ok(_) => println!("Error: n must be at least 1."),
            Err(_) => println!("Invalid input. Please enter a positive integer."),
        }
    };

    let mut solutions = Vec::new();
    backtrack(n, 0, &mut Vec::new(), &mut solutions);

    if solutions.is_empty() {
        println!("No solutions exist for a {}x{} board.", n, n);
    } else {
        println!("Found {} solutions:", solutions.len());
        for (i, solution) in solutions.iter().enumerate() {
            println!("Solution {}:", i + 1);
            for col in solution {
                println!("{}", (0..n).map(|c| if c == *col { "Q" } else { "." }).collect::<Vec<_>>().join(" "));
            }
            println!();
        }
    }
}

fn backtrack(n: usize, row: usize, queens: &mut Vec<usize>, solutions: &mut Vec<Vec<usize>>) {
    if row == n {
        solutions.push(queens.clone());
        return;
    }

    for col in 0..n {
        if is_safe(queens, row, col) {
            queens.push(col);
            backtrack(n, row + 1, queens, solutions);
            queens.pop();
        }
    }
}

fn is_safe(queens: &[usize], row: usize, col: usize) -> bool {
    for (r, &c) in queens.iter().enumerate() {
        if c == col || r + c == row + col || r as isize - c as isize == row as isize - col as isize {
            return false;
        }
    }
    true
}
