import sys

class UnionFind:
    def __init__(self):
        self.parent = {}
        self.rank = {}

    def add(self, x):
        if x not in self.parent:
            self.parent[x] = x
            self.rank[x] = 0

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        x_root = self.find(x)
        y_root = self.find(y)
        if x_root == y_root:
            return False
        if self.rank[x_root] < self.rank[y_root]:
            self.parent[x_root] = y_root
        else:
            self.parent[y_root] = x_root
            if self.rank[x_root] == self.rank[y_root]:
                self.rank[x_root] += 1
        return True

def main():
    if len(sys.argv) != 2:
        print("Usage: python mst.py <input_file>")
        sys.exit(1)

    input_file = sys.argv[1]
    cities = {}
    edges = {}

    with open(input_file, 'r') as f:
        for line_num, line in enumerate(f, 1):
            line = line.strip()
            if not line:
                continue
            parts = line.split()
            if parts[0].lower() == 'city':
                if len(parts) != 4:
                    raise ValueError(f"Line {line_num}: Invalid City format")
                name = parts[1]
                try:
                    x, y = float(parts[2]), float(parts[3])
                except ValueError:
                    raise ValueError(f"Line {line_num}: Invalid coordinates")
                if name in cities:
                    raise ValueError(f"Line {line_num}: Duplicate city {name}")
                cities[name] = (x, y)
            elif parts[0].lower() == 'edge':
                if len(parts) != 4:
                    raise ValueError(f"Line {line_num}: Invalid Edge format")
                city1, city2 = parts[1], parts[2]
                if city1 not in cities or city2 not in cities:
                    raise ValueError(f"Line {line_num}: Undefined city")
                try:
                    distance = float(parts[3])
                    if distance <= 0:
                        raise ValueError("Distance must be positive")
                except ValueError:
                    raise ValueError(f"Line {line_num}: Invalid distance")
                key = frozenset([city1, city2])
                if key in edges:
                    if distance < edges[key]:
                        edges[key] = distance
                else:
                    edges[key] = distance
            else:
                raise ValueError(f"Line {line_num}: Unknown command")

    edge_list = [(*key, val) for key, val in edges.items()]
    edge_list.sort(key=lambda x: x[2])

    uf = UnionFind()
    for city in cities:
        uf.add(city)

    mst = []
    for edge in edge_list:
        city1, city2, dist = edge[0], edge[1], edge[2]
        if uf.union(city1, city2):
            mst.append((city1, city2, dist))

    for city1, city2, dist in mst:
        print(f"{city1} - {city2} : {dist}")

if __name__ == "__main__":
    main()
