struct TrieNode {
    children: HashMap<char, TrieNode>,
    count: usize,
}

impl TrieNode {
    fn new() -> Self {
        TrieNode {
            children: HashMap::new(),
            count: 0,
        }
    }
}

struct Trie {
    root: TrieNode,
}

impl Trie {
    fn new() -> Self {
        Trie {
            root: TrieNode::new(),
        }
    }

    fn insert(&mut self, query: &str) -> Result<(), String> {
        if query.is_empty() {
            return Err("Query cannot be empty".to_string());
        }

        for c in query.chars() {
            if !c.is_ascii_lowercase() {
                return Err(format!("Invalid character '{}' in query", c));
            }
        }

        let mut node = &mut self.root;

        for c in query.chars() {
            node = node.children.entry(c).or_insert(TrieNode::new());
        }

        node.count += 1;
        Ok(())
    }

    fn search(&self, prefix: &str) -> Vec<(String, usize)> {
        let mut node = &self.root;

        for c in prefix.chars() {
            match node.children.get(&c) {
                Some(next_node) => node = next_node,
                None => return vec![],
            }
        }

        let mut results = Vec::new();
        let mut stack = vec![(node, String::new())];

        while let Some((current_node, current_suffix)) = stack.pop() {
            if current_node.count > 0 {
                results.push((current_suffix.clone(), current_node.count));
            }

            for (c, child_node) in &current_node.children {
                let new_suffix = format!("{}{}", current_suffix, c);
                stack.push((child_node, new_suffix));
            }
        }

        let mut suggestions: Vec<_> = results
            .into_iter()
            .map(|(suffix, count)| (format!("{}{}", prefix, suffix), count))
            .collect();

        suggestions.sort_by(|a, b| b.1.cmp(&a.1));

        suggestions
    }
}
