class Node {
    constructor() {
        this.children = {};
        this.indexes = [];
    }
}

class SuffixTree {
    constructor(str) {
        this.root = new Node();
        this.str = str;
        for (let i = 0; i < str.length; i++) {
            this.addSuffix(i);
        }
    }

    addSuffix(index) {
        let node = this.root;
        for (let i = index; i < this.str.length; i++) {
            const char = this.str[i];
            if (!node.children[char]) {
                node.children[char] = new Node();
            }
            node = node.children[char];
            node.indexes.push(index);
        }
    }

    findLongestRepeated() {
        let result = '';
        const stack = [[this.root, '']];
        while (stack.length) {
            const [node, path] = stack.pop();
            if (node.indexes.length > 1 && path.length > result.length) {
                result = path;
            }
            for (const [char, child] of Object.entries(node.children)) {
                stack.push([child, path + char]);
            }
        }
        return result;
    }
}

function findLongestRepeatedSubstring(filePath) {
    try {
        const input = fs.readFileSync(filePath, 'utf-8').trim();
        if (!input) throw new Error("Input string is empty.");
        const suffixTree = new SuffixTree(input);
        const longest = suffixTree.findLongestRepeated();
        return longest || null;
    } catch (error) {
        if (error.code === 'ENOENT') throw new Error("File not found.");
        if (error.message === "Input string is empty.") throw error;
        throw new Error("Error reading file.");
    }
}

