class Song {
    String title;
    String artist;
    Song prev;
    Song next;

    public Song(String title, String artist) {
        this.title = title;
        this.artist = artist;
    }
}

public class Playlist {
    private Song head;
    private Song tail;
    private int size;

    public void addSong(String title, String artist) {
        if (title == null || artist == null) {
            throw new IllegalArgumentException("Title and artist cannot be null");
        }
        if (searchByTitle(title) != null) {
            throw new IllegalArgumentException("Duplicate song title");
        }
        Song newSong = new Song(title, artist);
        if (head == null) {
            head = tail = newSong;
        } else {
            tail.next = newSong;
            newSong.prev = tail;
            tail = newSong;
        }
        size++;
    }

    public void removeSong(String title) {
        if (size == 0) {
            throw new IllegalStateException("Playlist is empty");
        }
        Song song = searchByTitle(title);
        if (song == null) {
            throw new IllegalArgumentException("Song not found");
        }
        if (song.prev != null) {
            song.prev.next = song.next;
        } else {
            head = song.next;
        }
        if (song.next != null) {
            song.next.prev = song.prev;
        } else {
            tail = song.prev;
        }
        size--;
    }

    public Song searchByTitle(String title) {
        Song current = head;
        while (current != null) {
            if (current.title.equals(title)) {
                return current;
            }
            current = current.next;
        }
        return null;
    }

    public void moveSongToPosition(String title, int position) {
        if (position < 0 || position >= size) {
            throw new IllegalArgumentException("Invalid position");
        }
        Song song = searchByTitle(title);
        if (song == null) {
            throw new IllegalArgumentException("Song not found");
        }
        removeSong(title);
        if (position == 0) {
            song.prev = null;
            song.next = head;
            if (head != null) {
                head.prev = song;
            }
            head = song;
            if (tail == null) {
                tail = song;
            }
        } else {
            Song current = head;
            for (int i = 0; i < position - 1; i++) {
                current = current.next;
            }
            song.prev = current;
            song.next = current.next;
            if (current.next != null) {
                current.next.prev = song;
            } else {
                tail = song;
            }
            current.next = song;
        }
        size++;
    }
}
