#include <stdexcept>
#include <string>

using namespace std;

const int N = 8;

vector<int> queens(N, -1);
vector<bool> col(N, false);
vector<bool> diag1(2 * N - 1, false);
vector<bool> diag2(2 * N - 1, false);

bool isSafe(int row, int col_idx) {
    return !col[col_idx] && !diag1[row - col_idx + N - 1] && !diag2[row + col_idx];
}

bool solve(int row) {
    if (row == N) return true;
    for (int c = 0; c < N; ++c) {
        if (isSafe(row, c)) {
            queens[row] = c;
            col[c] = diag1[row - c + N - 1] = diag2[row + c] = true;
            if (solve(row + 1)) return true;
            col[c] = diag1[row - c + N - 1] = diag2[row + c] = false;
            queens[row] = -1;
        }
    }
    return false;
}

void validate() {
    for (int i = 0; i < N; ++i) {
        for (int j = i + 1; j < N; ++j) {
            if (queens[i] == queens[j] || abs(i - j) == abs(queens[i] - queens[j]))
                throw runtime_error("Invalid configuration detected.");
        }
    }
}

void printBoard() {
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            cout << (queens[i] == j ? "Q " : ". ");
        }
        cout << '\n';
    }
}

int main() {
    try {
        if (!solve(0)) throw runtime_error("No valid solution.");
        validate();
        printBoard();
    } catch (const exception& e) {
        cerr << "Error: " << e.what() << endl;
        return 1;
    }
    return 0;
}
