import java.io.*;
import java.util.*;

public class ShellSortSalaries {

    public static void main(String[] args) {
        if (args.length == 0) {
            System.err.println("Usage: java ShellSortSalaries <csvfile>");
            return;
        }
        List<Integer> salaries = readSalariesFromCSV(args[0]);
        if (salaries.isEmpty()) return;

        List<Integer> shellGaps = generateShellGaps(salaries.size());
        List<Integer> copy1 = new ArrayList<>(salaries);
        shellSort(copy1, shellGaps);

        List<Integer> knuthGaps = generateKnuthGaps(salaries.size());
        List<Integer> copy2 = new ArrayList<>(salaries);
        shellSort(copy2, knuthGaps);
    }

    private static List<Integer> readSalariesFromCSV(String filename) {
        List<Integer> salaries = new ArrayList<>();
        try (BufferedReader br = new BufferedReader(new FileReader(filename))) {
            String line;
            while ((line = br.readLine()) != null) {
                String[] data = line.split(",");
                if (data.length == 0) continue;
                String val = data[data.length - 1].trim();
                try {
                    int salary = Integer.parseInt(val);
                    if (salary > 0) salaries.add(salary);
                    else System.err.println("Invalid salary: " + val);
                } catch (NumberFormatException e) {
                    System.err.println("Invalid format: " + val);
                }
            }
        } catch (FileNotFoundException e) {
            System.err.println("File not found: " + filename);
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
        return salaries;
    }

    public static void shellSort(List<Integer> list, List<Integer> gaps) {
        for (int gap : gaps) {
            for (int i = gap; i < list.size(); i++) {
                int temp = list.get(i);
                int j;
                for (j = i; j >= gap && list.get(j - gap) > temp; j -= gap) {
                    list.set(j, list.get(j - gap));
                }
                list.set(j, temp);
            }
        }
    }

    private static List<Integer> generateShellGaps(int n) {
        List<Integer> gaps = new ArrayList<>();
        for (int gap = n / 2; gap > 0; gap /= 2) {
            gaps.add(gap);
        }
        return gaps;
    }

    private static List<Integer> generateKnuthGaps(int n) {
        List<Integer> gaps = new ArrayList<>();
        int k = 1;
        while (true) {
            int gap = (int) ((Math.pow(3, k) - 1) / 2);
            if (gap > n / 3) break;
            gaps.add(gap);
            k++;
        }
        Collections.reverse(gaps);
        return gaps;
    }
}
