class TabHistory {
  constructor(initialUrl) {
    this.current = new Node(initialUrl);
  }

  navigateBackward() {
    if (!this.current) throw new Error("No tabs available");
    if (!this.current.prev) throw new Error("Cannot navigate backward");
    this.current = this.current.prev;
  }

  navigateForward() {
    if (!this.current) throw new Error("No tabs available");
    if (!this.current.next) throw new Error("Cannot navigate forward");
    this.current = this.current.next;
  }

  openNewTab(url) {
    const newNode = new Node(url);
    if (this.current === null) {
      this.current = newNode;
      return;
    }
    newNode.prev = this.current;
    this.current.next = newNode;
    this.current = newNode;
  }

  closeCurrentTab() {
    if (!this.current) throw new Error("No tab to close");
    const prevNode = this.current.prev;
    const nextNode = this.current.next;
    if (prevNode) prevNode.next = nextNode;
    if (nextNode) nextNode.prev = prevNode;
    this.current = prevNode !== null ? prevNode : nextNode;
  }
}
