using namespace std;

struct Student {
    string name;
    double gpa;
};

bool parseStudent(const string& line, Student& student) {
    stringstream ss(line);
    vector<string> tokens;
    string token;
    while (ss >> token) tokens.push_back(token);
    if (tokens.size() < 2) return false;

    try {
        size_t pos;
        student.gpa = stod(tokens.back(), &pos);
        if (pos != tokens.back().size() || student.gpa < 0.0 || student.gpa > 4.0) return false;
    } catch (...) { return false; }

    student.name = tokens[0];
    for (size_t i = 1; i < tokens.size() - 1; ++i)
        student.name += " " + tokens[i];
    return true;
}

bool readStudents(const string& filename, vector<Student>& students) {
    ifstream file(filename);
    if (!file.is_open()) return false;

    students.clear();
    string line;
    while (getline(file, line) && students.size() < 10000) {
        Student s;
        if (parseStudent(line, s)) students.push_back(s);
    }
    return true;
}

void selectionSort(vector<Student>& students) {
    int n = students.size();
    for (int i = 0; i < n - 1; ++i) {
        int maxIdx = i;
        for (int j = i + 1; j < n; ++j)
            if (students[j].gpa > students[maxIdx].gpa) maxIdx = j;
        if (maxIdx != i) swap(students[i], students[maxIdx]);
    }
}

void printStudents(const vector<Student>& students) {
    for (const auto& s : students)
        cout << s.name << " " << fixed << setprecision(1) << s.gpa << endl;
}

int main(int argc, char* argv[]) {
    if (argc != 2) {
        cerr << "Usage: " << argv[0] << " <filename>\n";
        return 1;
    }

    vector<Student> students;
    if (!readStudents(argv[1], students)) {
        cerr << "Error reading file.\n";
        return 1;
    }

    selectionSort(students);
    printStudents(students);
    return 0;
}
