class Dictionary {
  constructor() {
    this.size = 9973;
    this.storage = new Array(this.size).fill().map(() => []);
  }

  _hash(word) {
    let hash = 5381;
    for (let i = 0; i < word.length; i++) {
      hash = (hash * 33) ^ word.charCodeAt(i);
    }
    return Math.abs(hash) % this.size;
  }

  add(word, definition) {
    const index = this._hash(word);
    const bucket = this.storage[index];
    const existing = bucket.find(entry => entry.word === word);
    existing ? existing.definition = definition : bucket.push({ word, definition });
  }

  delete(word) {
    const index = this._hash(word);
    this.storage[index] = this.storage[index].filter(entry => entry.word !== word);
  }

  query(word) {
    const entry = this.storage[this._hash(word)].find(e => e.word === word);
    return entry ? entry.definition : undefined;
  }
}
