import java.util.*;

class PlayerLeaderboard {
    private HashMap<String, Integer> playerScores;
    private TreeMap<Integer, Integer> scoreCounts;

    public PlayerLeaderboard() {
        playerScores = new HashMap<>();
        scoreCounts = new TreeMap<>(Collections.reverseOrder());
    }

    public void addPlayer(String playerId, int score) {
        if (playerScores.containsKey(playerId)) {
            int oldScore = playerScores.get(playerId);
            int count = scoreCounts.get(oldScore);
            if (count == 1) scoreCounts.remove(oldScore);
            else scoreCounts.put(oldScore, count - 1);
        }
        playerScores.put(playerId, score);
        scoreCounts.put(score, scoreCounts.getOrDefault(score, 0) + 1);
    }

    public void deletePlayer(String playerId) {
        if (!playerScores.containsKey(playerId)) return;
        int score = playerScores.get(playerId);
        playerScores.remove(playerId);
        int count = scoreCounts.get(score);
        if (count == 1) scoreCounts.remove(score);
        else scoreCounts.put(score, count - 1);
    }

    public int getKthHighest(int k) {
        int accumulated = 0;
        for (Map.Entry<Integer, Integer> entry : scoreCounts.entrySet()) {
            accumulated += entry.getValue();
            if (accumulated >= k) return entry.getKey();
        }
        return -1;
    }
