#include <iostream>
#include <vector>
#include <cstdlib>
#include <ctime>
#include <limits>
#include <unordered_map>

using namespace std;

struct Node {
    string symbol;
    double price;
    vector<Node*> forward;
    Node(string s, double p, int level) : symbol(s), price(p), forward(level, nullptr) {}
};

class SkipList {
    int maxLevel;
    float probability;
    int currentMaxLevel;
    Node* head;

    int randomLevel() {
        int lvl = 1;
        while (((double)rand() / RAND_MAX) < probability && lvl < maxLevel)
            lvl++;
        return lvl;
    }

public:
    SkipList(int maxLvl = 16, float prob = 0.5) : maxLevel(maxLvl), probability(prob) {
        currentMaxLevel = 1;
        head = new Node("", 0.0, maxLevel);
    }

    ~SkipList() {
        Node* node = head->forward[0];
        while (node) {
            Node* next = node->forward[0];
            delete node;
            node = next;
        }
        delete head;
    }

    bool insert(string symbol, double price) {
        vector<Node*> update(maxLevel, nullptr);
        Node* current = head;

        for (int i = currentMaxLevel - 1; i >= 0; i--) {
            while (current->forward[i] && current->forward[i]->symbol < symbol)
                current = current->forward[i];
            update[i] = current;
        }

        current = current->forward[0];
        if (current && current->symbol == symbol) return false;

        int rLevel = randomLevel();
        if (rLevel > currentMaxLevel) {
            for (int i = currentMaxLevel; i < rLevel; i++)
                update[i] = head;
            currentMaxLevel = rLevel;
        }

        Node* newNode = new Node(symbol, price, rLevel);
        for (int i = 0; i < rLevel; i++) {
            newNode->forward[i] = update[i]->forward[i];
            update[i]->forward[i] = newNode;
        }
        return true;
    }

    bool deleteNode(string symbol) {
        vector<Node*> update(maxLevel, nullptr);
        Node* current = head;
        bool found = false;

        for (int i = currentMaxLevel - 1; i >= 0; i--) {
            while (current->forward[i] && current->forward[i]->symbol < symbol)
                current = current->forward[i];
            update[i] = current;
        }

        current = current->forward[0];
        if (current && current->symbol == symbol) found = true;
        if (!found) return false;

        for (int i = 0; i < currentMaxLevel; i++) {
            if (update[i]->forward[i] != current) break;
            update[i]->forward[i] = current->forward[i];
        }

        delete current;
        while (currentMaxLevel > 1 && head->forward[currentMaxLevel - 1] == nullptr)
            currentMaxLevel--;
        return true;
    }

    double search(string symbol) {
        Node* current = head;
        for (int i = currentMaxLevel - 1; i >= 0; i--) {
            while (current->forward[i] && current->forward[i]->symbol < symbol)
                current = current->forward[i];
        }
        current = current->forward[0];
        if (current && current->symbol == symbol) return current->price;
        return -1.0;
    }

    vector<pair<string, double>> getSortedStocks() {
        vector<pair<string, double>> result;
        Node* node = head->forward[0];
        while (node) {
            result.emplace_back(node->symbol, node->price);
            node = node->forward[0];
        }
        return result;
    }
};

int main() {
    srand(time(0));
    SkipList stockTracker;
    int choice;
    string symbol;
    double price;

    do {
        cout << "1. Insert Stock\n2. Delete Stock\n3. Search Stock\n4. Display Sorted Stocks\n5. Exit\nEnter choice: ";
        cin >> choice;
        cin.ignore(numeric_limits<streamsize>::max(), '\n');

        switch (choice) {
            case 1:
                cout << "Enter stock symbol: ";
                cin >> symbol;
                cout << "Enter price: ";
                cin >> price;
                if (stockTracker.insert(symbol, price))
                    cout << "Stock inserted.\n";
                else
                    cout << "Insert failed (duplicate?).\n";
                break;
            case 2:
                cout << "Enter stock symbol to delete: ";
                cin >> symbol;
                if (stockTracker.deleteNode(symbol))
                    cout << "Stock deleted.\n";
                else
                    cout << "Stock not found.\n";
                break;
            case 3:
                cout << "Enter stock symbol to search: ";
                cin >> symbol;
                price = stockTracker.search(symbol);
                if (price != -1.0)
                    cout << "Price: " << price << endl;
                else
                    cout << "Stock not found.\n";
                break;
            case 4: {
                auto stocks = stockTracker.getSortedStocks();
                cout << "Stocks sorted by symbol:\n";
                for (auto& s : stocks)
                    cout << s.first << " - " << s.second << endl;
                break;
            }
            case 5:
                cout << "Exiting.\n";
                break;
            default:
                cout << "Invalid choice.\n";
        }
    } while (choice != 5);

    return 0;
}
