use std::collections::HashMap;
use std::cmp::Ordering;

#[derive(Debug, Eq, PartialEq)]
struct Task {
    id: u32,
    priority: u32,
}

impl Ord for Task {
    fn cmp(&self, other: &Self) -> Ordering {
        self.priority.cmp(&other.priority)
    }
}

impl PartialOrd for Task {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

struct TaskScheduler {
    heap: Vec<Task>,
    map: HashMap<u32, usize>,
}

impl TaskScheduler {
    fn new() -> Self {
        TaskScheduler {
            heap: Vec::new(),
            map: HashMap::new(),
        }
    }

    fn insert(&mut self, task: Task) {
        let idx = self.heap.len();
        self.map.insert(task.id, idx);
        self.heap.push(task);
        self.sift_up(idx);
    }

    fn update_priority(&mut self, task_id: u32, new_priority: u32) {
        let idx = *self.map.get(&task_id).expect("Task not found");
        let old_priority = self.heap[idx].priority;
        self.heap[idx].priority = new_priority;

        if new_priority > old_priority {
            self.sift_up(idx);
        } else {
            self.sift_down(idx);
        }
    }

    fn pop_max(&mut self) -> Option<Task> {
        if self.heap.is_empty() {
            return None;
        }

        let task = self.heap.swap_remove(0);
        self.map.remove(&task.id);

        if !self.heap.is_empty() {
            let moved_id = self.heap[0].id;
            self.map.insert(moved_id, 0);
            self.sift_down(0);
        }

        Some(task)
    }

    fn sift_up(&mut self, mut idx: usize) {
        while idx > 0 {
            let parent_idx = (idx - 1) / 2;
            if self.heap[idx] > self.heap[parent_idx] {
                self.heap.swap(idx, parent_idx);
                self.map.insert(self.heap[idx].id, idx);
                self.map.insert(self.heap[parent_idx].id, parent_idx);
                idx = parent_idx;
            } else {
                break;
            }
        }
    }

    fn sift_down(&mut self, mut idx: usize) {
        let len = self.heap.len();
        while idx < len {
            let left = 2 * idx + 1;
            let right = 2 * idx + 2;
            let mut largest = idx;

            if left < len && self.heap[left] > self.heap[largest] {
                largest = left;
            }
            if right < len && self.heap[right] > self.heap[largest] {
                largest = right;
            }

            if largest != idx {
                self.heap.swap(idx, largest);
                self.map.insert(self.heap[idx].id, idx);
                self.map.insert(self.heap[largest].id, largest);
                idx = largest;
            } else {
                break;
            }
        }
    }
}
