@RestController
public class EncodingController {

    @PostMapping("/encode")
    public ResponseEntity<String> encodeFile(@RequestParam("file") MultipartFile file) {
        try (InputStream fileStream = file.getInputStream();
             ByteArrayOutputStream outputStream = new ByteArrayOutputStream()) {

            Base64.Encoder encoder = Base64.getEncoder();
            byte[] buffer = new byte[8192];
            int bytesRead;

            while ((bytesRead = fileStream.read(buffer)) != -1) {
                byte[] encodedChunk = encoder.encode(buffer, 0, bytesRead);
                outputStream.write(encodedChunk);
            }

            return ResponseEntity.ok(outputStream.toString("UTF-8"));
        } catch (IOException e) {
            return ResponseEntity.internalServerError().build();
        }
    }
