class AVLNode {
    constructor(score, userId) {
        this.score = score;
        this.userId = userId;
        this.left = null;
        this.right = null;
        this.height = 1;
        this.size = 1;
    }
}

class AVLTree {
    constructor() {
        this.root = null;
    }

    getHeight(node) {
        return node ? node.height : 0;
    }

    getSize(node) {
        return node ? node.size : 0;
    }

    update(node) {
        node.height = Math.max(this.getHeight(node.left), this.getHeight(node.right)) + 1;
        node.size = this.getSize(node.left) + this.getSize(node.right) + 1;
    }

    balanceFactor(node) {
        return this.getHeight(node.left) - this.getHeight(node.right);
    }

    rotateRight(y) {
        const x = y.left;
        const T2 = x.right;
        x.right = y;
        y.left = T2;
        this.update(y);
        this.update(x);
        return x;
    }

    rotateLeft(x) {
        const y = x.right;
        const T2 = y.left;
        y.left = x;
        x.right = T2;
        this.update(x);
        this.update(y);
        return y;
    }

    insertNode(node, score, userId) {
        if (!node) return new AVLNode(score, userId);
        if (score > node.score || (score === node.score && userId < node.userId)) {
            node.left = this.insertNode(node.left, score, userId);
        } else {
            node.right = this.insertNode(node.right, score, userId);
        }
        this.update(node);
        const balance = this.balanceFactor(node);
        if (balance > 1) {
            if (score > node.left.score || (score === node.left.score && userId < node.left.userId)) {
                return this.rotateRight(node);
            } else {
                node.left = this.rotateLeft(node.left);
                return this.rotateRight(node);
            }
        }
        if (balance < -1) {
            if (score < node.right.score || (score === node.right.score && userId > node.right.userId)) {
                return this.rotateLeft(node);
            } else {
                node.right = this.rotateRight(node.right);
                return this.rotateLeft(node);
            }
        }
        return node;
    }

    deleteNode(node, score, userId) {
        if (!node) return null;
        if (score > node.score || (score === node.score && userId < node.userId)) {
            node.left = this.deleteNode(node.left, score, userId);
        } else if (score < node.score || (score === node.score && userId > node.userId)) {
            node.right = this.deleteNode(node.right, score, userId);
        } else {
            if (!node.left || !node.right) {
                node = node.left || node.right;
            } else {
                let temp = node.right;
                while (temp.left) temp = temp.left;
                node.score = temp.score;
                node.userId = temp.userId;
                node.right = this.deleteNode(node.right, temp.score, temp.userId);
            }
        }
        if (!node) return null;
        this.update(node);
        const balance = this.balanceFactor(node);
        if (balance > 1) {
            if (this.balanceFactor(node.left) >= 0) {
                return this.rotateRight(node);
            } else {
                node.left = this.rotateLeft(node.left);
                return this.rotateRight(node);
            }
        }
        if (balance < -1) {
            if (this.balanceFactor(node.right) <= 0) {
                return this.rotateLeft(node);
            } else {
                node.right = this.rotateRight(node.right);
                return this.rotateLeft(node);
            }
        }
        return node;
    }

    insert(score, userId) {
        this.root = this.insertNode(this.root, score, userId);
    }

    delete(score, userId) {
        this.root = this.deleteNode(this.root, score, userId);
    }

    findRank(node, score, userId, rank = 0) {
        if (!node) return rank + 1;
        if (score > node.score || (score === node.score && userId < node.userId)) {
            return this.findRank(node.left, score, userId, rank);
        } else {
            return this.findRank(node.right, score, userId, rank + this.getSize(node.left) + 1);
        }
    }

    getRank(score, userId) {
        return this.findRank(this.root, score, userId);
    }
}

class Leaderboard {
    constructor() {
        this.scores = {};
        this.tree = new AVLTree();
    }

    updateScore(userId, score) {
        if (userId in this.scores) {
            const oldScore = this.scores[userId];
            this.tree.delete(oldScore, userId);
        }
        this.scores[userId] = score;
        this.tree.insert(score, userId);
    }

    getRank(userId) {
        if (!(userId in this.scores)) return -1;
        return this.tree.getRank(this.scores[userId], userId);
    }
}
