class OrderBook {
private:
    map<double, vector<Order>, greater<double>> bids;
    map<double, vector<Order>> asks;

    void validateOrder(const Order& order) {
        if (order.price <= 0 || order.quantity <= 0) {
            throw invalid_argument("Invalid price or quantity");
        }
    }

public:
    void addOrder(const Order& order) {
        validateOrder(order);
        if (order.type == OrderType::BID) {
            bids[order.price].push_back(order);
        } else {
            asks[order.price].push_back(order);
        }
    }

    vector<Order> queryPriceLevel(double price, OrderType type) {
        if (type == OrderType::BID) {
            auto it = bids.find(price);
            return it != bids.end() ? it->second : vector<Order>();
        } else {
            auto it = asks.find(price);
            return it != asks.end() ? it->second : vector<Order>();
        }
    }
};

