use std::collections::HashMap;
use std::fs::File;
use std::io::{self, BufRead, BufReader, Write};

struct TrieNode {
    children: HashMap<char, TrieNode>,
    is_end: bool,
}

impl TrieNode {
    fn new() -> Self {
        TrieNode {
            children: HashMap::new(),
            is_end: false,
        }
    }
}

struct Trie {
    root: TrieNode,
}

impl Trie {
    fn new() -> Self {
        Trie {
            root: TrieNode::new(),
        }
    }

    fn insert(&mut self, word: &str) {
        let mut node = &mut self.root;
        for c in word.chars() {
            node = node.children.entry(c).or_insert_with(TrieNode::new);
        }
        node.is_end = true;
    }

    fn get_words_with_prefix(&self, prefix: &str) -> Vec<String> {
        let mut results = Vec::new();
        let mut prefix_chars: Vec<char> = prefix.chars().collect();

        let start_node = if prefix.is_empty() {
            &self.root
        } else {
            let mut node = &self.root;
            for c in prefix.chars() {
                match node.children.get(&c) {
                    Some(n) => node = n,
                    None => return results,
                }
            }
            node
        };

        Self::collect_words(start_node, &mut prefix_chars, &mut results);
        results
    }

    fn collect_words(node: &TrieNode, prefix: &mut Vec<char>, results: &mut Vec<String>) {
        if node.is_end {
            results.push(prefix.iter().collect());
        }
        for (c, child) in &node.children {
            prefix.push(*c);
            Self::collect_words(child, prefix, results);
            prefix.pop();
        }
    }
}

fn load_words_from_file(file_path: &str, trie: &mut Trie) -> io::Result<()> {
    let file = File::open(file_path)?;
    let reader = BufReader::new(file);
    for line in reader.lines() {
        let word = match line {
            Ok(l) => l.trim().to_string(),
            Err(_) => continue,
        };
        if !word.is_empty() {
            trie.insert(&word);
        }
    }
    Ok(())
}

fn main() -> io::Result<()> {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 2 {
        eprintln!("Usage: {} <dictionary-file>", args[0]);
        std::process::exit(1);
    }

    let mut trie = Trie::new();
    if let Err(e) = load_words_from_file(&args[1], &mut trie) {
        eprintln!("Error loading file: {}", e);
        std::process::exit(1);
    }

    let stdin = io::stdin();
    let mut stdout = io::stdout();
    loop {
        print!("Enter prefix (type 'exit' to quit): ");
        stdout.flush()?;
        let mut input = String::new();
        stdin.read_line(&mut input)?;
        let prefix = input.trim();
        if prefix == "exit" {
            break;
        }
        let words = trie.get_words_with_prefix(prefix);
        println!("Matches: {:?}", words);
    }
    Ok(())
}
