    while (1) {
        int result = fscanf(file, "%d", &num);
        if (result == EOF) break;
        if (result != 1) {
            printf("Invalid input.\n");
            int c;
            do { c = fgetc(file); } while (c != EOF && !isspace(c));
        } else {
            if (num <= 0) printf("%d is invalid.\n", num);
            else printf("%d is %sprime.\n", num, is_prime(num) ? "" : "not ");
        }
    }

    fclose(file);
