use std::collections::LinkedList;
use std::sync::{Arc, Mutex};
use std::thread;

struct Task {
    priority: u32,
    description: String,
}

struct TaskManager {
    tasks: Arc<Mutex<LinkedList<Task>>>,
}

impl TaskManager {
    fn new() -> Self {
        TaskManager {
            tasks: Arc::new(Mutex::new(LinkedList::new())),
        }
    }

    fn add_task(&self, task: Task) {
        let mut tasks = self.tasks.lock().unwrap();
        let mut cursor = tasks.cursor_front_mut();
        let mut inserted = false;
        while let Some(current) = cursor.current() {
            if current.priority < task.priority {
                cursor.insert_before(task);
                inserted = true;
                break;
            }
            cursor.move_next();
        }
        if !inserted {
            tasks.push_back(task);
        }
    }

    fn remove_task(&self, priority: u32) -> Option<Task> {
        let mut tasks = self.tasks.lock().unwrap();
        let mut cursor = tasks.cursor_front_mut();
        while let Some(current) = cursor.current() {
            if current.priority == priority {
                return cursor.remove_current();
            }
            cursor.move_next();
        }
        None
    }

    fn get_highest_priority(&self) -> Option<Task> {
        let mut tasks = self.tasks.lock().unwrap();
        tasks.pop_front()
    }
}

fn main() {
    let manager = TaskManager::new();
    let handles: Vec<_> = (0..4)
        .map(|i| {
            let mgr = manager.tasks.clone();
            thread::spawn(move || {
                let task = Task {
                    priority: i,
                    description: format!("Task {}", i),
                };
                let manager = TaskManager { tasks: mgr };
                manager.add_task(task);
            })
        })
        .collect();
    for handle in handles {
        handle.join().unwrap();
    }
}
