#include <stdio.h>
#include <stdlib.h>
#include <string.h>

char* read_file(const char* filename) {
    FILE *file = fopen(filename, "r");
    if (!file) return NULL;

    fseek(file, 0, SEEK_END);
    long length = ftell(file);
    fseek(file, 0, SEEK_SET);

    char *buffer = malloc(length + 1);
    if (!buffer) { fclose(file); return NULL; }

    size_t bytes_read = fread(buffer, 1, length, file);
    buffer[length] = '\0';
    fclose(file);

    return (bytes_read == length) ? buffer : NULL;
}

char* lcs(const char* X, const char* Y) {
    int m = strlen(X), n = strlen(Y);
    int **dp = malloc((m+1) * sizeof(int*));
    for (int i=0; i<=m; i++) dp[i] = malloc((n+1) * sizeof(int));

    for (int i=0; i<=m; i++) {
        for (int j=0; j<=n; j++) {
            if (i==0 || j==0) dp[i][j] = 0;
            else if (X[i-1] == Y[j-1]) dp[i][j] = dp[i-1][j-1] + 1;
            else dp[i][j] = (dp[i-1][j] > dp[i][j-1]) ? dp[i-1][j] : dp[i][j-1];
        }
    }

    int index = dp[m][n];
    char *result = malloc(index + 1);
    result[index--] = '\0';

    int i = m, j = n;
    while (i > 0 && j > 0) {
        if (X[i-1] == Y[j-1]) {
            result[index--] = X[i-1];
            i--; j--;
        } else if (dp[i-1][j] > dp[i][j-1]) i--;
        else j--;
    }

    for (int i=0; i<=m; i++) free(dp[i]);
    free(dp);
    return result;
}

int main(int argc, char *argv[]) {
    char *current_lcs = NULL;

    for (int i=1; i<argc; i++) {
        char *content = read_file(argv[i]);
        if (!content) { fprintf(stderr, "Error reading %s\n", argv[i]); continue; }
        if (!current_lcs) current_lcs = content;
        else {
            char *new_lcs = lcs(current_lcs, content);
            free(current_lcs);
            free(content);
            current_lcs = new_lcs;
        }
    }

    char input[256];
    while (1) {
        printf("Enter filename (or 'exit'): ");
        if (!fgets(input, 256, stdin)) break;
        input[strcspn(input, "\n")] = '\0';
        if (strcmp(input, "exit") == 0) break;

        char *content = read_file(input);
        if (!content) { fprintf(stderr, "Error reading %s\n", input); continue; }

        if (!current_lcs) current_lcs = content;
        else {
            char *new_lcs = lcs(current_lcs, content);
            free(current_lcs);
            free(content);
            current_lcs = new_lcs;
        }
        printf("Current LCS: %s\n", current_lcs ? current_lcs : "");
    }

    free(current_lcs);
    return 0;
}
