#include <time.h>

#define MAX_HEAP_SIZE 100
#define MAX_PRIORITY 10
#define MIN_PRIORITY 1

typedef struct {
    int id;
    int priority;
    time_t arrival_time;
    char data[256];
} Packet;

typedef struct {
    Packet* heap[MAX_HEAP_SIZE];
    int size;
} PriorityQueue;

PriorityQueue* createQueue() {
