void swap(Packet** a, Packet** b) {
    Packet* temp = *a;
    *a = *b;
    *b = temp;
}

void heapifyUp(PriorityQueue* q, int index) {
    int parent = (index - 1) / 2;
    while (index > 0 && q->heap[parent]->priority < q->heap[index]->priority) {
        swap(&q->heap[parent], &q->heap[index]);
        index = parent;
        parent = (index - 1) / 2;
    }
}

void heapifyDown(PriorityQueue* q, int index) {
    int left, right, largest;
    while (1) {
        left = 2 * index + 1;
        right = 2 * index + 2;
        largest = index;

        if (left < q->size && q->heap[left]->priority > q->heap[largest]->priority)
            largest = left;
        if (right < q->size && q->heap[right]->priority > q->heap[largest]->priority)
            largest = right;

        if (largest != index) {
            swap(&q->heap[index], &q->heap[largest]);
            index = largest;
        } else {
            break;
        }
    }
}

int validatePacket(Packet* p) {
    if (p->priority < MIN_PRIORITY || p->priority > MAX_PRIORITY) {
        printf("Invalid priority %d for packet ID %d\n", p->priority, p->id);
        return 0;
    }
    return 1;
}

void enqueue(PriorityQueue* q, Packet* p) {
    if (!validatePacket(p)) {
        free(p);
        return;
    }
    if (q->size >= MAX_HEAP_SIZE) {
        printf("Queue is full. Packet ID %d dropped.\n", p->id);
        free(p);
        return;
    }
    q->heap[q->size] = p;
    q->size++;
    heapifyUp(q, q->size - 1);
    printf("Enqueued packet ID=%d, priority=%d\n", p->id, p->priority);
}

Packet* dequeue(PriorityQueue* q) {
    if (q->size == 0) {
        printf("Queue is empty.\n");
        return NULL;
    }
    Packet* max = q->heap[0];
    q->heap[0] = q->heap[q->size - 1];
    q->size--;
    heapifyDown(q, 0);
    printf("Dequeued packet ID=%d, priority=%d\n", max->id, max->priority);
    return max;
}

int main() {
    PriorityQueue* q = createQueue();
    srand(time(NULL));

    for (int i = 0; i < 5; i++) {
        Packet* p = (Packet*)malloc(sizeof(Packet));
        p->id = i;
        p->priority = rand() % 12;
        p->arrival_time = time(NULL);
        snprintf(p->data, sizeof(p->data), "Sample data %d", i);
        enqueue(q, p);
    }

    while (q->size > 0) {
        Packet* p = dequeue(q);
        free(p);
    }

    free(q);
    return 0;
}
