    let mut board = Vec::new();
    backtrack(n, &mut board, &mut solutions);
    println!("Found {} solutions", solutions.len());
    for (i, solution) in solutions.iter().enumerate() {
        println!("Solution {}:", i + 1);
        print_solution(solution);
        println!();
    }
}

fn backtrack(n: usize, board: &mut Vec<usize>, solutions: &mut Vec<Vec<usize>>) {
    if board.len() == n {
        solutions.push(board.clone());
        return;
    }
    for col in 0..n {
        if is_safe(board, col) {
            board.push(col);
            backtrack(n, board, solutions);
            board.pop();
        }
    }
}

fn is_safe(board: &[usize], col: usize) -> bool {
    let row = board.len();
    for (i, &queen_col) in board.iter().enumerate() {
        if queen_col == col || (row - i) == col.abs_diff(queen_col) {
            return false;
        }
    }
    true
}

fn print_solution(solution: &[usize]) {
    for row in 0..solution.len() {
        let queen_col = solution[row];
        let line = (0..solution.len())
            .map(|col| if col == queen_col { "Q" } else { "." })
            .collect::<Vec<_>>()
            .join(" ");
        println!("{}", line);
    }
}
