function findShortestPath(graph, start, end) {
    if (typeof graph !== 'object' || graph === null || Array.isArray(graph)) {
        throw new Error('Invalid graph');
    }
    if (!graph.hasOwnProperty(start) || !graph.hasOwnProperty(end)) {
        throw new Error('Start or end node not in graph');
    }
    for (const node in graph) {
        const edges = graph[node];
        for (const neighbor in edges) {
            if (typeof edges[neighbor] !== 'number' || edges[neighbor] < 0) {
                throw new Error('Invalid edge weight');
            }
        }
    }

    const distances = {};
    const previous = {};
    const queue = [];
    Object.keys(graph).forEach(node => {
        distances[node] = Infinity;
        previous[node] = null;
    });
    distances[start] = 0;
    queue.push({ node: start, distance: 0 });

    while (queue.length > 0) {
        queue.sort((a, b) => a.distance - b.distance);
        const current = queue.shift();

        if (current.distance > distances[current.node]) continue;
        if (current.node === end) break;

        const neighbors = graph[current.node];
        for (const neighbor in neighbors) {
            const alt = current.distance + neighbors[neighbor];
            if (alt < distances[neighbor]) {
                distances[neighbor] = alt;
                previous[neighbor] = current.node;
                queue.push({ node: neighbor, distance: alt });
            }
        }
    }

    if (distances[end] === Infinity) {
        throw new Error('End node is unreachable');
    }

    const path = [];
    let temp = end;
    while (temp !== null) {
        path.push(temp);
        temp = previous[temp];
    }
    path.reverse();

    return { path, distance: distances[end] };
}
