import java.io.IOException;
import java.nio.file.*;
import java.util.*;
import java.util.stream.Collectors;

public class ConfigurationManager {
    private volatile String[] valueArray;
    private volatile Map<String, Integer> keyIndexMap;
    private final Path configPath;
    private final Thread monitorThread;

    public ConfigurationManager(String filePath) throws IOException {
        configPath = Paths.get(filePath);
        initialize();
        monitorThread = new Thread(this::monitorConfig);
        monitorThread.setDaemon(true);
        monitorThread.start();
    }

    private void initialize() throws IOException {
        List<String> lines = Files.readAllLines(configPath);
        LinkedHashMap<String, String> configMap = new LinkedHashMap<>();

        for (int i = 0; i < lines.size(); i++) {
            String line = lines.get(i).trim();
            if (line.isEmpty() || line.startsWith("#")) continue;

            String[] parts = line.split("=", 2);
            if (parts.length != 2) {
                throw new IOException("Invalid format at line " + (i+1));
            }

            String key = parts[0].trim();
            String value = parts[1].trim();
            configMap.put(key, value);
        }

        valueArray = new String[configMap.size()];
        keyIndexMap = new HashMap<>(configMap.size());
        int idx = 0;
        for (Map.Entry<String, String> entry : configMap.entrySet()) {
            valueArray[idx] = entry.getValue();
            keyIndexMap.put(entry.getKey(), idx++);
        }
    }

    public String get(String key) {
        Integer idx = keyIndexMap.get(key);
        return idx != null ? valueArray[idx] : null;
    }

    private void monitorConfig() {
        try {
            WatchService watcher = FileSystems.getDefault().newWatchService();
            configPath.getParent().register(watcher, StandardWatchEventKinds.ENTRY_MODIFY);

            while (true) {
                WatchKey key = watcher.take();
                for (WatchEvent<?> event : key.pollEvents()) {
                    if (event.context().toString().equals(configPath.getFileName().toString())) {
                        initialize();
                        break;
                    }
                }
                key.reset();
            }
        } catch (Exception e) {
            Thread.currentThread().interrupt();
        }
    }
}
