#include <iostream>
#include <fstream>
#include <vector>
#include <algorithm>
#include <cstdlib>
#include "nlohmann/json.hpp"

using json = nlohmann::json;
using namespace std;

bool isSafe(int columns[], int row, int col) {
    for (int i = 0; i < 8; ++i) {
        if (columns[i] == -1) continue;
        if (columns[i] == col || abs(i - row) == abs(columns[i] - col)) return false;
    }
    return true;
}

void backtrack(vector<vector<int>>& solutions, int columns[], int row) {
    if (row == 8) {
        solutions.push_back(vector<int>(columns, columns + 8));
        return;
    }
    if (columns[row] != -1) {
        backtrack(solutions, columns, row + 1);
        return;
    }
    for (int col = 0; col < 8; ++col) {
        if (isSafe(columns, row, col)) {
            columns[row] = col;
            backtrack(solutions, columns, row + 1);
            columns[row] = -1;
        }
    }
}

int main(int argc, char* argv[]) {
    if (argc != 2) {
        cerr << "Usage: " << argv[0] << " <input.json>\n";
        return 1;
    }

    try {
        ifstream file(argv[1]);
        if (!file.is_open()) {
            cerr << "Error opening file.\n";
            return 1;
        }

        json data = json::parse(file);
        vector<pair<int, int>> initial_queens;

        if (!data.is_array()) {
            cerr << "Invalid JSON: expected array.\n";
            return 1;
        }

        for (auto& q : data) {
            int row = q["row"], col = q["col"];
            if (row < 0 || row >= 8 || col < 0 || col >= 8) {
                cerr << "Position out of bounds: (" << row << "," << col << ").\n";
                return 1;
            }
            initial_queens.emplace_back(row, col);
        }

        vector<bool> rows(8), cols(8);
        for (auto& q : initial_queens) {
            if (rows[q.first] || cols[q.second]) {
                cerr << "Duplicate row/column in input.\n";
                return 1;
            }
            rows[q.first] = cols[q.second] = true;
        }

        for (size_t i = 0; i < initial_queens.size(); ++i) {
            for (size_t j = i + 1; j < initial_queens.size(); ++j) {
                int dr = abs(initial_queens[i].first - initial_queens[j].first);
                int dc = abs(initial_queens[i].second - initial_queens[j].second);
                if (dr == dc) {
                    cerr << "Diagonal conflict detected.\n";
                    return 1;
                }
            }
        }

        int columns[8] = {-1,-1,-1,-1,-1,-1,-1,-1};
        for (auto& q : initial_queens)
            columns[q.first] = q.second;

        vector<vector<int>> solutions;
        backtrack(solutions, columns, 0);

        json output;
        for (auto& sol : solutions) {
            json solution;
            for (int row = 0; row < 8; ++row)
                solution.push_back({{"row", row}, {"col", sol[row]}});
            output.push_back(solution);
        }
        cout << output.dump(4) << endl;

    } catch (const json::parse_error& e) {
        cerr << "JSON error: " << e.what() << endl;
        return 1;
    } catch (const exception& e) {
        cerr << "Error: " << e.what() << endl;
        return 1;
    }

    return 0;
}
