#include <iostream>
#include <vector>
#include <stdexcept>
#include <algorithm>

using namespace std;

class PriorityQueue {
private:
    vector<int> heap;

    void heapifyUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / 2;
            if (heap[index] >= heap[parent]) break;
            swap(heap[index], heap[parent]);
            index = parent;
        }
    }

    void heapifyDown(int index) {
        int size = heap.size();
        while (true) {
            int left = 2 * index + 1;
            int right = 2 * index + 2;
            int smallest = index;
            if (left < size && heap[left] < heap[smallest])
                smallest = left;
            if (right < size && heap[right] < heap[smallest])
                smallest = right;
            if (smallest == index) break;
            swap(heap[index], heap[smallest]);
            index = smallest;
        }
    }

public:
    void insert(int value) {
        heap.push_back(value);
        heapifyUp(heap.size() - 1);
    }

    int extractMin() {
        if (heap.empty())
            throw underflow_error("Priority queue underflow");
        int minVal = heap[0];
        heap[0] = heap.back();
        heap.pop_back();
        if (!heap.empty())
            heapifyDown(0);
        return minVal;
    }

    int getMin() {
        if (heap.empty())
            throw underflow_error("Priority queue underflow");
        return heap[0];
    }

    bool isEmpty() const {
        return heap.empty();
    }
};

int main() {
    PriorityQueue pq;
    pq.insert(3);
    pq.insert(1);
    pq.insert(4);
    pq.insert(1);

    cout << "Minimum element: " << pq.getMin() << endl;

    while (!pq.isEmpty()) {
        cout << pq.extractMin() << " ";
    }
    cout << endl;

    try {
        pq.extractMin();
    } catch (const underflow_error& e) {
        cerr << "Error: " << e.what() << endl;
    }

    return 0;
}
