#include <iostream>
#include <vector>
#include <climits>

using namespace std;

int main() {
    int n;
    cin >> n;
    vector<vector<int>> dist(n, vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            cin >> dist[i][j];
        }
    }

    int max_mask = 1 << n;
    vector<vector<int>> dp(max_mask, vector<int>(n, INT_MAX));
    dp[1][0] = 0;

    for (int mask = 1; mask < max_mask; ++mask) {
        for (int i = 0; i < n; ++i) {
            if (!(mask & (1 << i))) continue;
            for (int j = 0; j < n; ++j) {
                if (mask & (1 << j)) continue;
                int new_mask = mask | (1 << j);
                if (dp[mask][i] != INT_MAX && dist[i][j] != INT_MAX) {
                    dp[new_mask][j] = min(dp[new_mask][j], dp[mask][i] + dist[i][j]);
                }
            }
        }
    }

    int result = INT_MAX;
    int full_mask = (1 << n) - 1;
    for (int i = 0; i < n; ++i) {
        if (dp[full_mask][i] != INT_MAX && dist[i][0] != INT_MAX) {
            result = min(result, dp[full_mask][i] + dist[i][0]);
        }
    }

    cout << result << endl;

    return 0;
}
